#!/usr/bin/env python3
from __future__ import annotations

import argparse
import json
import os
import sys
from datetime import datetime
from pathlib import Path
from typing import Any

os.environ.setdefault("LITELLM_LOCAL_MODEL_COST_MAP", "true")

WORKSPACE = Path.home() / ".openclaw" / "workspace"
REPORT_DIR = WORKSPACE / "research" / "reports"
CONFIG_PATH = WORKSPACE / "config" / "investment_research_event_triggers_v1.json"
INPUTS_CONFIG = WORKSPACE / "config" / "investment_research_org_inputs_v1.json"
DATA_SOURCE_POLICY = WORKSPACE / "config" / "investment_research_data_source_policy_v1.json"
SCRIPTS_DIR = WORKSPACE / "scripts"
QUANT_REPORT_DIR = WORKSPACE / "quant_projects" / "personal-a-share-research-system" / "research" / "reports"
RUNTIME_STATE_LATEST = QUANT_REPORT_DIR / "runtime_risk_state_latest.json"

sys.path.insert(0, str(SCRIPTS_DIR))
import run_investment_research_org_orchestrator as org  # noqa: E402
from investment_research_data_source_runtime import build_runtime_status, load_policy  # noqa: E402


def load_json(path: Path) -> dict[str, Any]:
    return json.loads(path.read_text(encoding="utf-8"))


def write_json(path: Path, payload: dict[str, Any]) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")


def compare_lists(a: list[str], b: list[str]) -> bool:
    return a != b


def parse_dt(value: Any) -> datetime:
    text = str(value or "").strip()
    if not text:
        return datetime.min
    for fmt in ("%Y-%m-%d %H:%M:%S", "%Y-%m-%dT%H:%M:%S.%f", "%Y-%m-%dT%H:%M:%S"):
        try:
            return datetime.strptime(text, fmt)
        except ValueError:
            continue
    return datetime.min


def load_runtime_overlay(date_tag: str) -> tuple[dict[str, Any], dict[str, Any]]:
    runtime_obj: dict[str, Any] = {}
    report_obj: dict[str, Any] = {}
    if RUNTIME_STATE_LATEST.exists():
        try:
            runtime_obj = load_json(RUNTIME_STATE_LATEST)
        except Exception:
            runtime_obj = {}
    report_path = QUANT_REPORT_DIR / f"today_stock_strategy_report_{date_tag}.json"
    if not report_path.exists():
        report_path = QUANT_REPORT_DIR / "today_stock_strategy_report_latest.json"
    if report_path.exists():
        try:
            report_obj = load_json(report_path)
        except Exception:
            report_obj = {}
    return runtime_obj, report_obj


def apply_runtime_overlay(summary: dict[str, Any]) -> dict[str, Any]:
    date_tag = str(summary.get("strategy_report_date_tag") or summary.get("paper_date_tag") or datetime.now().strftime("%Y%m%d"))
    today_tag = datetime.now().strftime("%Y%m%d")
    runtime_obj, report_obj = load_runtime_overlay(date_tag)
    latest_runtime = runtime_obj.get("latest_runtime") or {}

    # P1-001 修复：优先用 runtime_risk_state_latest 当日数据，忽略 paper_date_tag 的历史偏移
    # runtime_risk_state_latest.json 由 strategy_report 在每次运行后同步更新，
    # 其 date_tag 反映的是真实交易日期，不是 org module 的 paper_date_tag
    effective_date_tag = str(runtime_obj.get("date_tag") or "") if (str(runtime_obj.get("date_tag") or "") == today_tag and latest_runtime) else date_tag

    if str(runtime_obj.get("date_tag") or "") == effective_date_tag and latest_runtime:
        summary["risk_off"] = bool(latest_runtime.get("risk_off"))
        pe = dict(summary.get("paper_execution_status") or {})
        pe.update(
            {
                "source": "runtime_risk_state_latest",
                "mode": latest_runtime.get("mode"),
                "risk_off": latest_runtime.get("risk_off"),
                "hard_stop": latest_runtime.get("hard_stop"),
                "halt_new_buy": latest_runtime.get("halt_new_buy"),
                "halt_reason": latest_runtime.get("halt_reason"),
                "market_breadth": latest_runtime.get("market_breadth"),
                "gate_reasons": latest_runtime.get("gate_reasons") or [],
                "allowed_to_open_new_positions": not bool(latest_runtime.get("halt_new_buy")),
                "runtime_state_path": str(RUNTIME_STATE_LATEST),
            }
        )
        summary["paper_execution_status"] = pe
        source_paths = dict(summary.get("source_paths") or {})
        source_paths["runtime_risk_state_json"] = str(RUNTIME_STATE_LATEST)
        summary["source_paths"] = source_paths

    # 注意：第二个 overlay 块不得覆盖第一个 runtime_risk_state 块已设置的字段，
    # 因为 runtime_risk_state 含有盘中实时门控，比 morning strategy report 更新鲜。
    # 只在 runtime_risk_state 无数据时才用 strategy_report 的值做 fallback。
    trade_date_text = str(report_obj.get("trade_date") or "").replace("-", "")
    if trade_date_text == effective_date_tag and report_obj and not latest_runtime:
        pe = dict(summary.get("paper_execution_status") or {})
        pe.setdefault("source", "strategy_report")
        if report_obj.get("risk_mode") is not None:
            pe.setdefault("mode", report_obj.get("risk_mode"))
        if report_obj.get("risk_off") is not None:
            pe.setdefault("risk_off", report_obj.get("risk_off"))
            summary.setdefault("risk_off", bool(report_obj.get("risk_off")))
        if report_obj.get("hard_stop") is not None:
            pe.setdefault("hard_stop", report_obj.get("hard_stop"))
        if report_obj.get("halt_new_buy") is not None:
            pe.setdefault("halt_new_buy", report_obj.get("halt_new_buy"))
            pe.setdefault("allowed_to_open_new_positions", not bool(report_obj.get("halt_new_buy")))
        if report_obj.get("trigger_reason"):
            pe.setdefault("halt_reason", report_obj.get("trigger_reason"))
        if "market_breadth" in report_obj:
            pe.setdefault("market_breadth", report_obj.get("market_breadth"))
        summary["paper_execution_status"] = pe
    return summary


def should_reset_baseline(prev: dict[str, Any] | None, cur: dict[str, Any]) -> tuple[bool, str]:
    if not prev:
        return False, ""

    prev_dt = parse_dt(prev.get("generated_at"))
    if prev_dt != datetime.min and (datetime.now() - prev_dt).days >= 2:
        return True, "previous_state_stale"

    prev_source_paths = prev.get("source_paths", {}) or {}
    old_holdings = str(prev_source_paths.get("app_holdings_csv") or "")
    old_live_report = str(prev_source_paths.get("live_system_report") or "")
    if "ths_app_holdings_" in old_holdings or "live_system_v1" in old_live_report:
        return True, "previous_state_old_execution_regime"

    if not prev.get("paper_date_tag") and cur.get("paper_date_tag"):
        return True, "previous_state_missing_paper_baseline"

    prev_execution = prev.get("paper_execution_status", {}) or {}
    cur_execution = cur.get("paper_execution_status", {}) or {}
    if prev_execution.get("source") and prev_execution.get("source") != cur_execution.get("source"):
        return True, "execution_source_changed"

    return False, ""


def build_triggers(prev: dict[str, Any] | None, cur: dict[str, Any], rules: dict[str, Any], data_source_runtime: dict[str, Any] | None = None) -> list[dict[str, Any]]:
    triggers: list[dict[str, Any]] = []
    if prev is None:
        return triggers

    if rules.get("audit_not_pass") and cur.get("audit_status") != "PASS":
        triggers.append({"type": "audit_not_pass", "detail": f"audit_status={cur.get('audit_status')}"})

    if rules.get("precheck_changed") and prev.get("precheck_status") != cur.get("precheck_status"):
        triggers.append({"type": "precheck_changed", "detail": f"{prev.get('precheck_status')} -> {cur.get('precheck_status')}"})

    if rules.get("risk_off_flip") and prev.get("risk_off") != cur.get("risk_off"):
        triggers.append({"type": "risk_off_flip", "detail": f"{prev.get('risk_off')} -> {cur.get('risk_off')}"})

    if rules.get("priority_tickers_changed") and compare_lists(prev.get("priority_tickers", []), cur.get("priority_tickers", [])):
        triggers.append({"type": "priority_tickers_changed", "detail": f"{prev.get('priority_tickers', [])} -> {cur.get('priority_tickers', [])}"})

    holdings_delta = abs((cur.get("holdings_rows") or 0) - (prev.get("holdings_rows") or 0))
    if holdings_delta >= rules.get("holdings_rows_delta_threshold", 999999):
        triggers.append({"type": "holdings_rows_changed", "detail": f"Δholdings_rows={holdings_delta}"})

    trades_delta = abs((cur.get("trades_rows") or 0) - (prev.get("trades_rows") or 0))
    if trades_delta >= rules.get("trades_rows_delta_threshold", 999999):
        triggers.append({"type": "trades_rows_changed", "detail": f"Δtrades_rows={trades_delta}"})

    mdd_prev = prev.get("max_drawdown_pct")
    mdd_cur = cur.get("max_drawdown_pct")
    if isinstance(mdd_prev, (int, float)) and isinstance(mdd_cur, (int, float)):
        delta = abs(mdd_cur - mdd_prev)
        if delta >= rules.get("max_drawdown_delta_threshold", 999999):
            triggers.append({"type": "max_drawdown_changed", "detail": f"Δmax_drawdown={delta:.2f}"})

    sharpe_prev = prev.get("sharpe")
    sharpe_cur = cur.get("sharpe")
    if isinstance(sharpe_prev, (int, float)) and isinstance(sharpe_cur, (int, float)):
        delta = abs(sharpe_cur - sharpe_prev)
        if delta >= rules.get("sharpe_delta_threshold", 999999):
            triggers.append({"type": "sharpe_changed", "detail": f"Δsharpe={delta:.3f}"})

    if rules.get("data_source_health_watch") and data_source_runtime:
        ds_status = str(data_source_runtime.get("status", ""))
        should_trigger_data_source_watch = ds_status == "degraded" or (ds_status == "watch_guarded" and bool(cur.get("trading_time")))
        if should_trigger_data_source_watch:
            triggers.append({"type": "data_source_health_watch", "detail": f"status={ds_status}; reason={data_source_runtime.get('reason', '-')}"})

    return triggers


def render_markdown(status: str, summary: dict[str, Any], prev: dict[str, Any] | None, triggers: list[dict[str, Any]], should_meet: bool, data_source_runtime: dict[str, Any] | None = None) -> str:
    lines: list[str] = []
    lines.append("# 来福投研会 - 临时会商触发监控")
    lines.append("")
    lines.append(f"- 生成时间：{summary['generated_at']}")
    lines.append(f"- 监控状态：`{status}`")
    lines.append(f"- 是否建议临时会商：`{should_meet}`")
    lines.append("")
    lines.append("## 当前快照")
    lines.append(f"- 审计状态：`{summary.get('audit_status', 'unknown')}`")
    lines.append(f"- 盘前强检：`{summary.get('precheck_status', 'unknown')}`")
    lines.append(f"- 风险收缩：`{summary.get('risk_off', '-')}`")
    pe = summary.get("paper_execution_status") or {}
    lines.append(f"- 执行模式：`{pe.get('mode', '-')}`")
    lines.append(f"- 是否允许新开仓：`{pe.get('allowed_to_open_new_positions', '-')}`")
    lines.append(f"- 优先候选：{', '.join(summary.get('priority_display', [])) if summary.get('priority_display') else '暂无'}")
    lines.append(f"- 持仓/成交行数：`{summary.get('holdings_rows', '-')}` / `{summary.get('trades_rows', '-')}`")
    if data_source_runtime:
        lines.append(f"- 数据源状态：`{data_source_runtime.get('status', '-')}`")
        lines.append(f"- 数据源判定：`{data_source_runtime.get('reason', '-')}`")
    lines.append("")
    if prev:
        lines.append("## 上一状态")
        lines.append(f"- 上次监控时间：`{prev.get('generated_at', '-')}`")
        lines.append(f"- 上次风险收缩：`{prev.get('risk_off', '-')}`")
        prev_disp = prev.get('priority_display', []) or []
        prev_tickers = prev.get('priority_tickers', []) or []
        lines.append(f"- 上次优先候选：{', '.join(prev_disp) if prev_disp else ', '.join(prev_tickers) if prev_tickers else '暂无'}")
        lines.append("")
    lines.append("## 触发项")
    if triggers:
        for item in triggers:
            lines.append(f"- `{item['type']}`：{item['detail']}")
    else:
        lines.append("- 本轮无触发项")
    lines.append("")
    lines.append("## 结论")
    if should_meet:
        lines.append("- 建议：触发临时会商，由首席研究员汇总并决定是否发起额外研究/风控审查。")
    else:
        lines.append("- 建议：继续常规值班，不必额外开会。")
    lines.append("")
    return "\n".join(lines) + "\n"


def _is_trading_day_now() -> bool:
    """用腾讯行情 API 判断当前是否为 A 股交易日。"""
    try:
        import urllib.request
        req = urllib.request.Request(
            "https://qt.gtimg.cn/q=sh000001",
            headers={"User-Agent": "Mozilla/5.0"},
        )
        with urllib.request.urlopen(req, timeout=5) as resp:
            content = resp.read().decode("gbk", errors="replace")
        for line in content.split(";"):
            if "sh000001" in line:
                parts = line.split("~")
                if len(parts) > 30:
                    mkt_str = parts[30].strip()[:8]
                    market_date = f"{mkt_str[:4]}-{mkt_str[4:6]}-{mkt_str[6:8]}"
                    today = datetime.now().strftime("%Y-%m-%d")
                    return market_date == today
                break
        return datetime.now().weekday() < 5
    except Exception:
        return datetime.now().weekday() < 5


def main() -> None:
    ap = argparse.ArgumentParser(description="Watch event triggers for temporary investment research meetings")
    ap.add_argument("--force-baseline", action="store_true")
    args = ap.parse_args()

    if not _is_trading_day_now():
        now = datetime.now()
        weekday = ["周一", "周二", "周三", "周四", "周五", "周六", "周日"][now.weekday()]
        print(f"[{now:%Y-%m-%d %H:%M}] 非 A 股交易日（{weekday}），跳过临时会商监控。", flush=True)
        return

    cfg = load_json(CONFIG_PATH)
    state_path = Path(cfg["statePath"])
    prev = load_json(state_path) if state_path.exists() and not args.force_baseline else None

    inputs_cfg = load_json(INPUTS_CONFIG)
    snapshot = org.build_input_snapshot(inputs_cfg)
    summary = org.make_summary(snapshot, datetime.now())
    summary = apply_runtime_overlay(summary)

    baseline_reset, baseline_reason = should_reset_baseline(prev, summary)
    if args.force_baseline or baseline_reset:
        prev = None

    policy = load_policy(DATA_SOURCE_POLICY)
    meeting_type = "midday" if summary.get("trading_time") else "night"
    data_source_runtime = build_runtime_status(policy, summary=summary, role_ids=["chief_researcher", "risk_officer", "trader"], meeting_type=meeting_type)

    triggers = build_triggers(prev, summary, cfg.get("rules", {}), data_source_runtime)
    if prev is None:
        status = "baseline_reset" if (args.force_baseline or baseline_reset) else "baseline_initialized"
    elif triggers:
        status = "triggered"
    else:
        status = "no_trigger"

    trigger_types = [t["type"] for t in triggers]
    should_meet = any(t in cfg.get("temporaryMeeting", {}).get("triggerOn", []) for t in trigger_types)

    now = datetime.now()
    md_path = REPORT_DIR / f"investment_research_event_watch_{now:%Y%m%d}.md"
    json_path = REPORT_DIR / f"investment_research_event_watch_{now:%Y%m%d}.json"
    payload = {
        "generated_at": summary["generated_at"],
        "status": status,
        "should_temporary_meet": should_meet,
        "triggers": triggers,
        "baseline_reset": baseline_reset or args.force_baseline,
        "baseline_reset_reason": baseline_reason if baseline_reset else ("force_baseline" if args.force_baseline else ""),
        "current": summary,
        "previous": prev,
        "data_source_runtime": data_source_runtime,
    }
    md_path.write_text(render_markdown(status, summary, prev, triggers, should_meet, data_source_runtime), encoding="utf-8")
    write_json(json_path, payload)
    write_json(state_path, summary)

    print(md_path)
    print(json_path)
    print(state_path)


if __name__ == "__main__":
    main()

