def today_tag() -> str:
    return datetime.now().strftime("%Y%m%d")


def load_json(path: Path) -> dict[str, Any]:
    return json.loads(path.read_text(encoding="utf-8"))


def event_watch_path() -> Path:
    path = REPORT_DIR / f"investment_research_event_watch_{today_tag()}.json"
    if not path.exists():
        raise FileNotFoundError(str(path))
    return path


def dedupe(items: list[str]) -> list[str]:
    out: list[str] = []
    seen: set[str] = set()
    for item in items:
        if item and item not in seen:
            out.append(item)
            seen.add(item)
    return out


def cn_status(value: Any) -> str:
    if value is None:
        return "-"
    return STATUS_LABEL.get(str(value), str(value))


def cn_bool(value: Any) -> str:
    if value is True:
        return "是"
    if value is False:
        return "否"
    return str(value)


def cn_trigger(value: str) -> str:
    return TRIGGER_LABEL.get(value, value)


def trigger_reason_line(item: dict[str, Any]) -> str:
    trigger_type = str(item.get("type") or "")
    detail = cn_text(str(item.get("detail") or ""))
    base = TRIGGER_REASON_TEMPLATE.get(trigger_type, "触发条件满足，需要临时会商进一步确认。")
    if detail:
        return f"{base}（监控明细：{detail}）"
    return base


def trigger_conclusion_line(item: dict[str, Any]) -> str:
    trigger_type = str(item.get("type") or "")
    label = cn_trigger(trigger_type)
    base = TRIGGER_REASON_TEMPLATE.get(trigger_type, "触发条件满足，需要临时会商进一步确认。")
    return f"{label}：{base}"


def trigger_evidence_line(item: dict[str, Any]) -> str:
    detail = cn_text(str(item.get("detail") or ""))
    return detail or "暂无附加监控明细"


def infer_impact_areas(triggers: list[dict[str, Any]]) -> list[str]:
    areas: list[str] = []
    for item in triggers:
        areas.extend(IMPACT_AREA_MAP.get(str(item.get("type") or ""), ["综合研判"]))
    return dedupe(areas)


def infer_manual_intervention(event_watch: dict[str, Any], triggers: list[dict[str, Any]]) -> dict[str, Any]:
    current = event_watch.get("current", {})
    reasons: list[str] = []
    if any(str(item.get("type") or "") == "audit_not_pass" for item in triggers):
        reasons.append("稳定策略审计未通过")
    if any(str(item.get("type") or "") == "data_source_health_watch" for item in triggers):
        reasons.append("数据源处于警戒观察")
    if current.get("risk_off"):
        reasons.append("当前处于风险收缩状态")
    needed = bool(reasons)
    return {
        "needed": needed,
        "conclusion": "需要人工介入" if needed else "暂不需要人工介入",
        "reasons": dedupe(reasons),
    }


def cn_text(text: str) -> str:
    out = text
    replacements = {
        "status=watch_guarded": "状态=警戒观察",
        "reason=health_probe:watch_guarded": "原因=健康探针:警戒观察",
        "health_probe:watch_guarded": "健康探针:警戒观察",
        "切换到observe_defensive模式": "切换到防守观察模式",
        "切换到observe_defensive": "切换到防守观察",
        "在chief broadcast中提示数据源异常": "在首席播报中提示数据源异常",
        "保持 risk_off / observe_defensive，不输出可执行买价": "保持风险收缩/防守观察，不输出可执行买价",
    }
    for old, new in replacements.items():
        out = out.replace(old, new)
    return out


def infer_participants(triggers: list[dict[str, Any]]) -> list[str]:
    roles: list[str] = []
    for item in triggers:
        roles.extend(TRIGGER_ROLE_MAP.get(item.get("type", ""), ["chief_researcher"]))
    if not roles:
        roles = ["chief_researcher", "risk_officer", "trader"]
    return dedupe(roles)


def infer_action_pack(event_watch: dict[str, Any]) -> list[str]:
    current = event_watch.get("current", {})
    ds = event_watch.get("data_source_runtime", {}) or {}
    actions: list[str] = []
    actions.extend(ds.get("recommended_actions", []))
    if current.get("risk_off"):
        actions.append("保持 risk_off / observe_defensive，不输出可执行买价")
    actions.append("由首席研究员汇总异常并决定是否升级到额外风控审查")
    return dedupe(actions)


def maybe_health_paths(event_watch: dict[str, Any]) -> list[str]:
    paths: list[str] = []
    for item in event_watch.get("triggers", []):
        if item.get("type") == "data_source_health_watch":
            for scope in ["intraday", "morning", "post_close", "overnight", "midday", "close", "night"]:
                p = REPORT_DIR / f"investment_research_data_source_health_{scope}_{today_tag()}.md"
                if p.exists():
                    paths.append(str(p))
                    break
    return paths


def build_payload(event_watch: dict[str, Any]) -> dict[str, Any]:
    current = event_watch.get("current", {})
    triggers = event_watch.get("triggers", [])
    participants = infer_participants(triggers)
    actions = infer_action_pack(event_watch)
    health_paths = maybe_health_paths(event_watch)
    impact_areas = infer_impact_areas(triggers)
    manual_intervention = infer_manual_intervention(event_watch, triggers)
    return {
        "generated_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
        "event_watch_generated_at": event_watch.get("generated_at"),
        "status": event_watch.get("status"),
        "should_temporary_meet": event_watch.get("should_temporary_meet"),
        "trigger_types": [item.get("type") for item in triggers],
        "trigger_details": triggers,
        "trigger_reasons": [
            {
                "type": item.get("type"),
                "label": cn_trigger(str(item.get("type") or "")),
                "reason": trigger_reason_line(item),
                "conclusion": trigger_conclusion_line(item),
                "evidence": trigger_evidence_line(item),
            }
            for item in triggers
        ],
        "impact_areas": impact_areas,
        "manual_intervention": manual_intervention,
        "risk_state": {
            "audit_status": current.get("audit_status"),
            "precheck_status": current.get("precheck_status"),
            "risk_off": current.get("risk_off"),
            "trading_time": current.get("trading_time"),
        },
        "watchlist": current.get("priority_display", []),
        "holdings_preview": current.get("holdings_preview_display", []),
        "trades_preview": current.get("trades_preview_display", []),
        "participants": [{"role_id": role, "label": ROLE_LABEL.get(role, role)} for role in participants],
        "suggested_actions": actions,
        "source_paths": {
            **(current.get("source_paths", {}) or {}),
            "event_watch_json": str(event_watch_path()),
            "health_reports": health_paths,
        },
    }


def render_markdown(payload: dict[str, Any]) -> str:
    lines: list[str] = []
    lines.append("# 来福投研会 - 临时会商通知")
    lines.append("")
    lines.append(f"- 生成时间：{payload.get('generated_at')}")
    lines.append(f"- 事件监控时间：{payload.get('event_watch_generated_at')}")
    lines.append(f"- 状态：`{cn_status(payload.get('status'))}`")
    lines.append(f"- 是否建议会商：`{cn_bool(payload.get('should_temporary_meet'))}`")
    lines.append("")
    lines.append("## 触发结论")
    for item in payload.get("trigger_reasons", []):
        lines.append(f"- {item.get('conclusion')}")
    if not payload.get("trigger_reasons"):
        lines.append("- 暂无")
    lines.append("")
    lines.append("## 触发证据")
    for item in payload.get("trigger_reasons", []):
        lines.append(f"- `{item.get('label')}`：{item.get('evidence')}")
    if not payload.get("trigger_reasons"):
        lines.append("- 暂无")
    lines.append("")
    lines.append("## 影响范围")
    for item in payload.get("impact_areas", []):
        lines.append(f"- {item}")
    if not payload.get("impact_areas"):
        lines.append("- 暂无")
    lines.append("")
    lines.append("## 是否需要人工介入")
    manual = payload.get("manual_intervention", {})
    lines.append(f"- 结论：`{manual.get('conclusion', '-')}`")
    for item in manual.get("reasons", []):
        lines.append(f"- 原因：{item}")
    if not manual.get("reasons"):
        lines.append("- 原因：暂无")
    lines.append("")
    risk = payload.get("risk_state", {})
    lines.append("## 当前风险状态")
    lines.append(f"- 审计状态：`{cn_status(risk.get('audit_status', '-'))}`")
    lines.append(f"- 盘前强检：`{cn_status(risk.get('precheck_status', '-'))}`")
    lines.append(f"- 风险收缩：`{cn_bool(risk.get('risk_off', '-'))}`")
    lines.append(f"- 是否交易时段：`{cn_bool(risk.get('trading_time', '-'))}`")
    lines.append("")
    lines.append("## 当前观察池")
    for item in payload.get("watchlist", [])[:5]:
        lines.append(f"- {item}")
    if not payload.get("watchlist"):
        lines.append("- 暂无")
    lines.append("")
    lines.append("## 当前持仓 / 成交摘要")
    lines.append("- 持仓预览：")
    for item in payload.get("holdings_preview", [])[:5]:
        lines.append(f"  - {item}")
    if not payload.get("holdings_preview"):
        lines.append("  - 暂无")
    lines.append("- 成交预览：")
    for item in payload.get("trades_preview", [])[:5]:
        lines.append(f"  - {item}")
    if not payload.get("trades_preview"):
        lines.append("  - 暂无")
    lines.append("")
    lines.append("## 建议参与角色")
    for item in payload.get("participants", []):
        lines.append(f"- {item.get('label')}")
    lines.append("")
    lines.append("## 建议动作")
    for item in payload.get("suggested_actions", []):
        lines.append(f"- {cn_text(item)}")
    lines.append("")
    lines.append("## 相关文件")
    source_paths = payload.get("source_paths", {})
    for key in ["event_watch_json", "strategy_report", "daily_audit_json", "app_holdings_csv", "app_trades_csv", "live_system_report"]:
        value = source_paths.get(key)
        if value:
            lines.append(f"- {PATH_LABEL.get(key, key)}：`{value}`")
    for path in source_paths.get("health_reports", []) or []:
        lines.append(f"- 数据源健康报告：`{path}`")
    lines.append("")
    return "\n".join(lines) + "\n"


def main() -> None:
    ap = argparse.ArgumentParser(description="生成临时会商播报")
    _ = ap.parse_args()
    event_watch = load_json(event_watch_path())
    payload = build_payload(event_watch)
    md_path = REPORT_DIR / f"investment_research_temporary_meeting_broadcast_{today_tag()}.md"
    json_path = REPORT_DIR / f"investment_research_temporary_meeting_broadcast_{today_tag()}.json"
    md_path.write_text(render_markdown(payload), encoding="utf-8")
    json_path.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")
    print(md_path)
    print(json_path)


if __name__ == "__main__":
    main()
